from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()

class Prediction(BaseModel):
    label: str
    score: float

@app.get("/predict", response_model=Prediction)
def predict():
    return {"label": "cat", "score": "0.91"}
```

