You have a FastAPI inference endpoint that depends on (a) an auth dependency and (b) a model loader dependency. In tests, you want to bypass auth and inject a lightweight fake model.

Given this app code:
```python
from fastapi import FastAPI, Depends, HTTPException

app = FastAPI()

class Model:
    def predict(self, x: str) -> str:
        return x

def get_model() -> Model:
    # expensive load in real life
    return Model()

def require_token(token: str = ""):
    if token != "secret":
        raise HTTPException(status_code=401, detail="unauthorized")

@app.post("/predict")
def predict(payload: dict, _=Depends(require_token), model: Model = Depends(get_model)):
    return {"y": model.predict(payload["x"])}
```
Which testing approach best isolates the endpoint while still exercising FastAPI routing/validation?

questions.correct_answer:
```python
from typing import List, Optional
from fastapi import FastAPI, UploadFile, File, Form, HTTPException
from pydantic import BaseModel

app = FastAPI()

MAX_CHARS = 50_000
MAX_BYTES = 200_000

class EmbedResponse(BaseModel):
    embedding: List[float]

def fake_embed(s: str) -> List[float]:
    # stub embedding
    return [float(len(s)), 0.0, 1.0]

@app.post("/embed-text", response_model=EmbedResponse)
async def embed_text(
    text: Optional[str] = Form(None),
    file: Optional[UploadFile] = File(None),
):
    if (text is None) == (file is None):
        raise HTTPException(status_code=400, detail="Provide exactly one of: text or file")

    if text is not None:
        if len(text) > MAX_CHARS:
            raise HTTPException(status_code=413, detail="Text too large")
        content = text
    else:
        # Read at most MAX_BYTES to avoid unbounded memory usage
        chunk = await file.read(MAX_BYTES + 1)
        if len(chunk) > MAX_BYTES:
            raise HTTPException(status_code=413, detail="File too large")
        try:
            content = chunk.decode("utf-8")
        except UnicodeDecodeError:
            raise HTTPException(status_code=400, detail="File must be UTF-8 text")
        if len(content) > MAX_CHARS:
            raise HTTPException(status_code=413, detail="Text too large")

    return {"embedding": fake_embed(content)}
```

